SELECT count(*) FROM kind_type, title, cast_info, movie_info, movie_keyword, name, info_type, movie_companies, keyword WHERE title.kind_id = kind_type.id AND cast_info.movie_id = title.id AND movie_info.movie_id = title.id AND movie_keyword.movie_id = title.id AND cast_info.person_id = name.id AND movie_info.info_type_id = info_type.id AND movie_companies.movie_id = title.id AND movie_keyword.keyword_id = keyword.id;